// hooks/useAdminOrders.js
import { useState, useEffect } from 'react';
import { fetchOrders } from '../api/orders';

export function useAdminOrders({ 
  date, 
  groupBy = null,    // 'item' | 'driver' | 'order' | null
  filterFn = null    // optional custom filter
}) {
  const [orders, setOrders] = useState([]);
  const [grouped, setGrouped] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (!date) return;

    setLoading(true);
    fetchOrders({ date })
      .then(data => {
        const filtered = filterFn ? data.filter(filterFn) : data;
        setOrders(filtered);

        if (groupBy) {
          setGrouped(groupOrdersBy(filtered, groupBy));
        }
      })
      .catch(setError)
      .finally(() => setLoading(false));
  }, [date, groupBy]);

  return { orders, grouped, loading, error };
}

// utils/groupOrders.js
export function groupOrdersBy(orders, key) {
  switch (key) {
    case 'item':
      return orders.reduce((acc, order) => {
        order.items.forEach(item => {
          acc[item.name] = acc[item.name] || [];
          acc[item.name].push({ ...item, order });
        });
        return acc;
      }, {});

    case 'driver':
      return orders.reduce((acc, order) => {
        const driver = order.driver?.name ?? 'Unassigned';
        acc[driver] = acc[driver] || [];
        acc[driver].push(order);
        return acc;
      }, {});

    case 'order':
      return orders.reduce((acc, order) => {
        acc[order.id] = order;
        return acc;
      }, {});

    default:
      throw new Error(`Unknown groupBy key: ${key}`);
  }
}
```

